      const raw = ICO[name] || '';
      const attrMatch = raw.match(/<svg([^>]*)>/);
      const origAttrs = attrMatch ? attrMatch[1].replace(/\s*(viewBox|width|height)="[^"]*"/g, '') : '';
      const inner = (raw.match(/<svg[^>]*>([\s\S]*)<\/svg>/) || [, ''])[1];
